/* Tier-2 C-level fixture: HTIF file I/O round-trip with self-validation.
 *
 * fopen/fwrite/fseek/fread/fclose all bottom out into libgloss's HTIF path
 * (frontend_syscall -> magicmem packet -> 0xE008_0010 -> vsim's sim_control
 * dispatch -> host syscall -> reply). Validation is in-program: on byte
 * mismatch rt_fail() writes SimCommand::FAILED to sim_control so vsim exits
 * with code 1 before handoff and the harness reports the failure.
 *
 * The path is fixed and the test self-unlinks. CTest serializes by default
 * so a fixed name is fine for our use.
 */
#include "runtime/rt_c_helpers.h"

#include <stdio.h>
#include <string.h>
#include <unistd.h>

#define PATH "/tmp/rt_c_file_io.tmp"
static const char payload[] = "vsim-htif file-io round-trip 0123456789\n";

int main(void)
{
  rt_phase_qemu1_drain();
  setvbuf(stdout, NULL, _IONBF, 0);

  FILE* fp = fopen(PATH, "w+");
  if (!fp) {
    printf("FAIL fopen\n");
    rt_fail();
  }

  if (fwrite(payload, 1, sizeof payload - 1, fp) != sizeof payload - 1) {
    printf("FAIL fwrite\n");
    rt_fail();
  }

  if (fseek(fp, 0, SEEK_SET) != 0) {
    printf("FAIL fseek\n");
    rt_fail();
  }

  char buf[sizeof payload];
  size_t n = fread(buf, 1, sizeof payload - 1, fp);
  if (n != sizeof payload - 1) {
    printf("FAIL fread n=%zu\n", n);
    rt_fail();
  }

  if (memcmp(buf, payload, sizeof payload - 1) != 0) {
    printf("FAIL memcmp\n");
    rt_fail();
  }

  if (fclose(fp) != 0) {
    printf("FAIL fclose\n");
    rt_fail();
  }

  if (unlink(PATH) != 0) {
    printf("FAIL unlink\n");
    rt_fail();
  }

  printf("rt_c_file_io: %zu bytes round-tripped\n", n);

  rt_phase_vsim_drain();
  return 0;
}

