1	/* Tier-2 C-level fixture: 16x16x16 GEMM split across all three phases.
2	 *
3	 *   QEMU 1: init_matrices -- fills A and B with deterministic patterns.
4	 *   vsim:   matmul_kernel -- the only phase that touches sim_control via
5	 *           printf(); also computes C = A * B.
6	 *   QEMU 2: prints C row-by-row via RISC-V semihosting (SYS_WRITE0,
7	 *           QEMU virt has no sim_control), then re-derives the expected
8	 *           value of every C[i][j] and compares. Mismatch -> _exit(1).
9	 *
10	 * Cross-phase memory survival
11	 *   vsim's elf loader (utils/elf_loader.hpp:94) zero-fills (memsz - filesz)
12	 *   for every PT_LOAD on resume, which would blow away anything in .bss
13	 *   that QEMU 1 had written. The matrices therefore live at fixed addresses
14	 *   (0x80100000+) -- inside the 128 MiB shared mmap, above the ELF's last
15	 *   loaded byte (~0x8000d800), below the stack (0x80700000), so QEMU's
16	 *   -kernel load and vsim's loader both leave them untouched. The shared
17	 *   memory-backend-file then preserves the bytes across QEMU1 -> vsim ->
18	 *   QEMU2.
19	 */
20	#include "runtime/rt_c_helpers.h"
21	
22	#include <stdint.h>
23	#include <stdio.h>
24	
25	#define N 16
26	
27	/* Fixed-address scratch region. Pointers (not arrays) so the compiler
28	 * doesn't reserve .bss for them. */
29	static int32_t* const A = (int32_t*) 0x80100000UL;
30	static int32_t* const B = (int32_t*) 0x80101000UL;
31	static int32_t* const C = (int32_t*) 0x80102000UL;
32	
33	#define AT(M, i, j) ((M)[(i) *N + (j)])
34	
35	static void init_matrices(void)
36	{
37	  for (int i = 0; i < N; i++) {
38	    for (int j = 0; j < N; j++) {
39	      AT(A, i, j) = (int32_t) ((i + j) % 7);
40	      AT(B, i, j) = (int32_t) ((i * 3 + j) % 5);
41	    }
42	  }
43	}
44	
45	static void matmul_kernel(void)
46	{
47	  for (int i = 0; i < N; i++) {
48	    for (int j = 0; j < N; j++) {
49	      int32_t s = 0;
50	      for (int k = 0; k < N; k++) {
51	        s += AT(A, i, k) * AT(B, k, j);
52	      }
53	      AT(C, i, j) = s;
54	    }
55	  }
56	}
57	
58	/* Independent recomputation in QEMU2 -- catches any kernel error. */
59	static int verify(void)
60	{
61	  for (int i = 0; i < N; i++) {
62	    for (int j = 0; j < N; j++) {
63	      int32_t s = 0;
64	      for (int k = 0; k < N; k++) {
65	        s += AT(A, i, k) * AT(B, k, j);
66	      }
67	      if (AT(C, i, j) != s)
68	        return 0;
69	    }
70	  }
71	  return 1;
72	}
