__attribute__((used)) int _rename(const char* old_name, const char* new_name)
{
  return SYSCALL_2(21, old_name, new_name);
}

__attribute__((used)) int _unlink(const char* file_name)
{
  return SYSCALL_1(22, file_name);
}

__attribute__((used, noreturn)) void _exit(int exit_status)
{
  /* In the hybrid round-trip flow, _exit is only reached in QEMU 2 (vsim
     itself terminates at the csrwi 0x7C0, 1 drain marker, well before main
     returns). QEMU 2 has -semihosting-config enable=on,target=native, so
     SYS_EXIT_EXTENDED reaches the host with the right status. The ebreak
     triple matches hybrid/test/semihost_exit.inc.

     We deliberately do NOT also poke EXIT_COMMAND_ADDR (0xE0080000) here:
     QEMU virt doesn't ignore that write -- it raises a store-access-fault
     that traps to m_trap_entry -> exception_handler, which reads Andes-only
     mdcause (CSR 0x7C9) on default -cpu rv64 and re-traps forever.

     If a fixture needs to fail-fast inside vsim, use rt_fail() in
     runtime/rt_c_helpers.h, which writes SimCommand::FAILED to sim_control
     directly and short-circuits the round-trip. */
  static volatile uint64_t semihost_block[2];
  semihost_block[0] = 0x20026; /* ADP_Stopped_ApplicationExit */
  semihost_block[1] = (uint64_t)(uint32_t) exit_status;
  register long a0 __asm__("a0") = 0x20; /* SYS_EXIT_EXTENDED */
  register long a1 __asm__("a1") = (long)(uintptr_t) semihost_block;
  __asm__ __volatile__(
    ".option push\n"
    ".option norvc\n"
    "slli x0, x0, 0x1f\n"
    "ebreak\n"
    "srai x0, x0, 0x7\n"
    ".option pop\n"
    : : "r"(a0), "r"(a1) : "memory");

  __asm__ __volatile__("1: j 1b");
  __builtin_unreachable();
}

__attribute__((used)) void* _sbrk(intptr_t increment)
{
  extern char _end[];
  static char* p = _end;
  void* base = p;
  p += increment;
  return base;
}

#ifdef __cplusplus
}
#endif

// Shared exit-via-semihosting macro for hybrid round-trip fixtures.
//
// SEMIHOST_EXIT exit_reg
//   Builds the {reason=ADP_Stopped_ApplicationExit, exit_code=<exit_reg>}
//   16-byte block at 0x80001000, sets a0=SYS_EXIT_EXTENDED (0x20), a1=block,
//   then issues the RISC-V semihosting `slli x0,x0,0x1f; ebreak; srai x0,x0,0x7`
//   triple. exit_reg may be any GPR holding the desired host exit code; this
//   macro clobbers t0, t1, a0, a1.
//
// QEMU's host-exit returns the low 8 bits of <exit_reg> as the process status.

.macro SEMIHOST_EXIT exit_reg
    li      t0, 0x80001000
    li      t1, 0x20026                     // ADP_Stopped_ApplicationExit
    sd      t1, 0(t0)
    sd      \exit_reg, 8(t0)
    li      a0, 0x20                        // SYS_EXIT_EXTENDED
    mv      a1, t0
    .option push
    .option norvc
    slli    x0, x0, 0x1f
    ebreak
    srai    x0, x0, 0x7
    .option pop
99: j       99b
.endm

// rt_csr_survival.S
//
// Tier-1 fixture: M-mode CSRs survive QEMU1 -> vsim -> QEMU2.
// Verifies the CSR pass-through merge in HandoffController and the
// feature-aware P-packet path in qemu_handback.
//
// Phase A (QEMU1): write distinguishable values to mscratch, mtvec, and
//                  mepc, then trigger the entry handoff.
// Phase B (vsim):  no-op.  vsim does not modify these CSRs; they must
//                  pass through the input-state snapshot kept by
//                  HandoffController and arrive at QEMU 2 unchanged.
// Phase C (QEMU2): csrr each CSR back into a GPR, compare. Exit code is
//                  the CSR index of the first mismatch (1=mscratch,
//                  2=mtvec, 3=mepc), 0 on full pass.
//
// mtvec is written with a 4-byte aligned value (mode=Direct) so QEMU
// accepts it without rounding the low bits.

#include "semihost_exit.inc"

.section .text
.globl _start
_start:
    li      t0, 0xCAFEBABEDEADBEEF
    csrw    mscratch, t0             // mscratch <- 0xCAFE...

    li      t0, 0x80000004           // 4-byte aligned, mode=Direct
    csrw    mtvec,    t0

    li      t0, 0x80100100
    csrw    mepc,     t0

.globl _hybrid_enter_pc
_hybrid_enter_pc:
    csrwi   0x7C0, 0                 // QEMU1 drains all of the above

.globl _hybrid_exit_pc
_hybrid_exit_pc:
    csrwi   0x7C0, 1                 // vsim drains, exits 200

phase_c:
    csrr    t1, mscratch
    li      t2, 0xCAFEBABEDEADBEEF
    bne     t1, t2, fail_mscratch

    csrr    t1, mtvec
    li      t2, 0x80000004
    bne     t1, t2, fail_mtvec

    csrr    t1, mepc
    li      t2, 0x80100100
    bne     t1, t2, fail_mepc

    li      a2, 0
    SEMIHOST_EXIT a2

fail_mscratch: li a2, 1; SEMIHOST_EXIT a2
fail_mtvec:    li a2, 2; SEMIHOST_EXIT a2
fail_mepc:     li a2, 3; SEMIHOST_EXIT a2

