/* Hello-world fixture using the toolchain's virtual-hosting libgloss
 * (libgloss_vh.a). All I/O goes through standard newlib printf, whose
 * _write bottoms out in the RISC-V semihosting magic triple -- handled
 * by QEMU1 / QEMU2 (both launched with -semihosting-config enable=on),
 * never invoked inside the vsim span.
 *
 * Build: -nodefaultlibs + -lc -lgloss_vh -lgcc. No runtime/libgloss.c
 * is linked, so the binary carries no vsim-specific MMIO paths.
 */
#include "runtime/rt_c_helpers.h"
#include <stdio.h>

int main(void)
{
  printf("hello from QEMU1\n");
  fflush(stdout);

  rt_phase_qemu1_drain();
  /* Phase 2 (vsim): no syscalls. */
  rt_phase_vsim_drain();

  printf("hello from QEMU2\n");
  fflush(stdout);
  return 0;
}

