/* Minimal trap glue for vh fixtures.
 *
 * The standard runtime/handler.c builds an ecall syscall-dispatch table
 * that references _open / _read / _access / ... -- symbols not provided
 * by libgloss_vh (vh routes syscalls through the semihosting magic
 * triple, intercepted by QEMU before reaching mtvec, so no ecall table
 * is needed). This file replaces handler.c for vh-linked builds and
 * only does the two things crt0+trap.S require:
 *   - init_mtvec(): point mtvec at m_trap_entry (constructor)
 *   - handle_trap(): bail out via _exit on any unexpected trap
 */
#include <stdint.h>

extern void m_trap_entry(void);
extern void _exit(int) __attribute__((noreturn));

void handle_trap(unsigned long cause, void* tf)
{
  (void) cause;
  (void) tf;
  _exit(1);
}

