/* Right-justified 4-char decimal cell + space, no printf. */
static int format_cell(char* dst, int32_t v)
{
  char tmp[12];
  int t = 0, neg = v < 0;
  uint32_t uv = neg ? -(uint32_t) v : (uint32_t) v;
  if (uv == 0)
    tmp[t++] = '0';
  while (uv) {
    tmp[t++] = (char) ('0' + (uv % 10));
    uv /= 10;
  }
  if (neg)
    tmp[t++] = '-';
  int p = 0;
  for (int pad = 4 - t; pad > 0; pad--)
    dst[p++] = ' ';
  while (t--)
    dst[p++] = tmp[t];
  dst[p++] = ' ';
  return p;
}

