// Shared GDB register-name tables. Used by the QEMU TCG plugin (C) at
// drain time and by vsim's gdbstub handback client (C++) at restore
// time. The strings are the gdb wire contract for QEMU's RISC-V
// gdbstub - any reordering or renaming must be done in lock-step here.

#ifndef HYBRID_REG_NAMES_H
#define HYBRID_REG_NAMES_H

#ifdef __cplusplus
extern "C" {
#endif

// Index = x register index. From riscv-64bit-cpu.xml.
static const char *const hybrid_gpr_names[32] = {
    "zero", "ra",  "sp",  "gp",  "tp",  "t0", "t1", "t2",
    "s0",   "s1",  "a0",  "a1",  "a2",  "a3", "a4", "a5",
    "a6",   "a7",  "s2",  "s3",  "s4",  "s5", "s6", "s7",
    "s8",   "s9",  "s10", "s11", "t3",  "t4", "t5", "t6",
};

// Index = f register index. From riscv-64bit-fpu.xml.
static const char *const hybrid_fpr_names[32] = {
    "ft0", "ft1", "ft2",  "ft3",  "ft4", "ft5", "ft6", "ft7",
    "fs0", "fs1", "fa0",  "fa1",  "fa2", "fa3", "fa4", "fa5",
    "fa6", "fa7", "fs2",  "fs3",  "fs4", "fs5", "fs6", "fs7",
    "fs8", "fs9", "fs10", "fs11", "ft8", "ft9", "ft10","ft11",
};

#ifdef __cplusplus
}  // extern "C"
#endif

#endif  // HYBRID_REG_NAMES_H

