  if (elf.header().identity_data() != ELF::ELF_DATA::ELFDATA2LSB) [[unlikely]]
    throw std::runtime_error("Only little-endian executables are supported");

  if (elf.header().machine_type() != ELF::ARCH::EM_RISCV) [[unlikely]]
    throw std::runtime_error("Not EM_RISCV");

  for (const auto& seg: elf.segments()) {
    if (seg.type() != ELF::SEGMENT_TYPES::PT_LOAD)
      continue;

    const auto paddr = boost::numeric_cast<xlen_t>(seg.physical_address());
    const auto memsz = boost::numeric_cast<xlen_t>(seg.virtual_size());
    const auto filesz = boost::numeric_cast<xlen_t>(seg.physical_size());
    spdlog::info("loading segment: addr={:#x}, memsz={}, filesz={}", paddr,
                 memsz, filesz);

    if (memsz > std::numeric_limits<xlen_t>::max() - paddr)
      throw std::runtime_error("PT_LOAD address overflow");
    if (paddr < base_addr || paddr + memsz >= base_addr + buf.size())
      throw std::runtime_error("PT_LOAD is not contained within memory region");

    const auto offset = paddr - base_addr;
    std::copy_n(seg.content().begin(), filesz, buf.subspan(offset).begin());
    if (memsz > filesz)
      std::fill_n(buf.subspan(offset + filesz).begin(), memsz - filesz, 0);
  }
}

inline void read_binary_file(const std::string& path, auto&& setter)
{
  std::ifstream file(path, std::ios::binary);
  if (!file)
    throw std::runtime_error("Failed to open file: " + path);

  std::vector<uint8_t> data((std::istreambuf_iterator<char>(file)),
                            std::istreambuf_iterator<char>());
  setter(data);
  spdlog::info("Loaded {} bytes from {}", data.size(), path);
}

