1	/* C-runtime linker script for hybrid round-trip fixtures.
2	 *
3	 * Loads at 0x80000000 (QEMU virt RAM base, also inside vsim's RAM region
4	 * RAM_BASE..RAM_END = 0x0..0x8FFFFFFF). Preserves .data/.bss/.rodata so C
5	 * programs with global state can link, and exposes _edata/_end (consumed by
6	 * crt0.S's bss-clear loop) and _stack (consumed by crt0.S's sp init).
7	 */
8	
9	ENTRY(_start)
10	
11	SECTIONS {
12	    . = 0x80000000;
13	
14	    .text : {
15	        *(.text.init)
16	        *(.text*)
17	    }
18	
19	    .rodata : {
20	        *(.rodata*)
21	        *(.srodata*)
22	    }
23	
24	    .data : {
25	        *(.data*)
26	        *(.sdata*)
27	    }
28	    _edata = .;
29	
30	    .bss : {
31	        *(.bss*)
32	        *(.sbss*)
33	        *(COMMON)
34	    }
35	    _end = .;
36	
37	    /* _stack sits in QEMU virt's default 128 MiB RAM (0x80000000..0x88000000)
38	     * and inside vsim RAM. Override at link time with -Wl,--defsym,_stack=...
39	     * if you change QEMU -m or vsim memory layout. */
40	    PROVIDE(_stack = 0x80700000);
41	}
42

