inline auto spawn_qemu(const std::string& binary,
                       const std::string& elf,
                       uint16_t gdb_port,
                       const std::string& shared_mem_path = {},
                       uint64_t shared_mem_size = 0) -> pid_t
{
  const pid_t pid = ::fork();
  if (pid < 0)
    throw std::runtime_error(std::string{"spawn_qemu: fork: "}
                             + std::strerror(errno));
  if (pid == 0) {
    // Detach the child from the caller's tty. -nographic makes QEMU's
    // chardev backend tcsetattr() stdin into raw mode; if the caller is
    // launched from a non-foreground process group (e.g. under timeout(1)),
    // that touch raises SIGTTOU/SIGTTIN and stops QEMU 2, hanging vsim's
    // waitpid. /dev/null sidesteps the tty entirely.
    const int devnull = ::open("/dev/null", O_RDONLY | O_CLOEXEC);
    if (devnull >= 0) {
      ::dup2(devnull, STDIN_FILENO);
      ::close(devnull);
    }

    const std::string gdb_arg = "tcp::" + std::to_string(gdb_port);
    const std::string mem_obj = "memory-backend-file,id=mem,share=on,mem-path="
                              + shared_mem_path
                              + ",size=" + std::to_string(shared_mem_size);
    std::vector<const char*> argv;
    argv.push_back(binary.c_str());
    if (!shared_mem_path.empty()) {
      argv.push_back("-object");
      argv.push_back(mem_obj.c_str());
      argv.push_back("-machine");
      argv.push_back("virt,memory-backend=mem");
    } else {
      argv.push_back("-M");
      argv.push_back("virt");
    }
    // -cpu andes-ax45mpv,vlen=512: matches QEMU 1's CPU and the vsim RTL
    // build (NDS_VLEN 512). Without this, QEMU 2 defaults to plain rv64
    // (no V), mstatus.VS becomes read-only zero, and vsetvli traps with
    // illegal-instruction as soon as a V-using fixture's Phase 3 runs.
    // Andes vendor CSRs touched by the runtime crt0 (mcache_ctl, mmisc_ctl,
    // ...) are also gated here.
    argv.push_back("-cpu");
    argv.push_back("andes-ax45mpv,vlen=512");
    argv.push_back("-bios");
    argv.push_back("none");
    argv.push_back("-nographic");
    argv.push_back("-semihosting-config");
    argv.push_back("enable=on,target=native");
    argv.push_back("-kernel");
    argv.push_back(elf.c_str());
    argv.push_back("-gdb");
    argv.push_back(gdb_arg.c_str());
    argv.push_back("-S");
    argv.push_back(nullptr);

    ::execv(binary.c_str(), const_cast<char* const*>(argv.data()));
    std::fprintf(stderr, "exec %s: %s\n", binary.c_str(),
                 std::strerror(errno));
    ::_exit(127);
  }
  return pid;
}

