/* Tier-2 fixture: regression for the "no redundant ELF reload" rule.
 *
 *   QEMU 1: seeds `static uint32_t buf[N]` in .bss with a deterministic
 *           pattern.
 *   vsim:   crosses the enter_vsim/exit_vsim boundary without touching buf.
 *   QEMU 2: reads buf back and verifies the pattern.
 *
 * Without the rule, vsim's elf_loader and QEMU 2's `-kernel` both
 * `std::fill_n(memsz - filesz, 0)` over the PT_LOAD covering .bss,
 * wiping the phase-1 seed. With the rule, the shared mmap retains the
 * bytes across phases 1->2->3 and the verification passes.
 *
 * Memory layout: buf lives in .bss inside the shared mmap (allocated by
 * the linker right after .data; see rt_c.ld). Stack is at 0x80700000. */

#include "runtime/rt_c_helpers.h"

#include <stdint.h>
#include <stdio.h>

#define N 64

static uint32_t buf[N];

static uint32_t pattern(int i)
{
  return (uint32_t)((uint32_t) i * 0xDEADBEEFu + 0x12345678u);
}

int main(void)
{
  for (int i = 0; i < N; i++)
    buf[i] = pattern(i);

  enter_vsim();
  /* Phase 2: no-op. The whole point is to verify that crossing the
   * vsim boundary does not zero .bss. */
  exit_vsim();

  for (int i = 0; i < N; i++) {
    const uint32_t exp = pattern(i);
    if (buf[i] != exp) {
      printf("rt_c_static_buf: FAIL i=%d exp=0x%08x got=0x%08x\n",
             i, exp, buf[i]);
      fflush(stdout);
      return 1;
    }
  }
  printf("rt_c_static_buf: PASS\n");
  fflush(stdout);
  return 0;
}

