void apply_resume_from_qemu(const std::string& path)
{
  hybrid::SystemCDmiBus<PLATFORM::dmi_addr_width, PLATFORM::dmi_data_width>
    bus{platform.dmi, platform.clk.period()};
  hybrid_input_state_ = hybrid::load_state(path);
  hybrid::ResumeDriver driver(bus);
  driver.resume(*hybrid_input_state_);
  // Stage V-register bytes into the fixed scratch region of RAM so the
  // fixture's vsim-phase prologue (vle8.v vN, (scratch)) can repopulate
  // v0..v31 from QEMU 1's snapshot. Best-effort: mismatched RAM layouts
  // throw, which is louder than silently dropping V state.
  if ((hybrid_input_state_->flags & HYBRID_FLAG_V) != 0u) {
    hybrid::stage_v_to_scratch(
      *hybrid_input_state_,
      platform.main_memory.data,
      platform.main_memory.region.base_address);
  }
}

