/* Tier-2 C-level fixture: 16x16x16 GEMM via RVV intrinsics, split across
 * the three handoff phases.
 *
 *   QEMU 1: init_matrices -- RVV vid.v + vadd.vx + vrem.vx fills A and B.
 *           V instructions retire just before the entry drain, exercising
 *           the plugin's HandoffSite translation-time PC capture (the
 *           old qemu_plugin_read_register("pc") path lagged for V).
 *   vsim:   vmatmul_kernel -- RVV outer-product GEMM (vle32 + vmacc.vx +
 *           vse32). V instructions also straddle the exit drain.
 *   QEMU 2: scalar_matmul_verify -- pure C reference recomputation, then
 *           cell-by-cell compare against vsim's C. Mismatch -> PASS=0.
 *
 * RVV shape
 *   VLEN=512, e32, LMUL=1 -> vlmax = 16 elements per V reg, exactly one
 *   row of a 16-wide matrix. The kernel runs N outer iterations (one per
 *   row of A), each accumulating into a single V register seeded to zero
 *   and storing it back as one row of C. No mask register, no tail policy
 *   subtlety: the vl set by vsetvli equals N for every iteration.
 *
 * Cross-phase memory survival (same convention as rt_c_matmul.c)
 *   Matrices sit in .bss. The "no redundant ELF reload" rule (vsim
 *   skips load_elf and QEMU 2 drops -kernel when --shared-mem-path is
 *   set) keeps phase-1 .bss writes intact through the shared
 *   memory-backend-file.
 */
#include "runtime/rt_c_helpers.h"

#include <riscv_vector.h>
#include <stdint.h>
#include <stdio.h>

#define N 16

static int32_t A[N * N];
static int32_t B[N * N];
static int32_t C[N * N];

#define AT(M, i, j) ((M)[(i) *N + (j)])

/* Vectorized init: one V register holds [0, 1, ..., N-1], reused across
 * rows. Per row i: A[i][:] = (vidx + i)   % 7, B[i][:] = (vidx + 3i) % 5.
 * vid.v writes unsigned lane indices; reinterpret to signed so the rest of
 * the math (and the int32_t* matrix pointers) stay in i32 land. */
static void init_matrices(void)
{
  size_t           vl     = __riscv_vsetvl_e32m1((size_t) N);
  const vuint32m1_t vidx_u = __riscv_vid_v_u32m1(vl);
  const vint32m1_t  vidx   = __riscv_vreinterpret_v_u32m1_i32m1(vidx_u);

  for (int i = 0; i < N; i++) {
    vint32m1_t va = __riscv_vadd_vx_i32m1(vidx, i, vl);
    va            = __riscv_vrem_vx_i32m1(va, 7, vl);
    __riscv_vse32_v_i32m1(&AT(A, i, 0), va, vl);

    vint32m1_t vb = __riscv_vadd_vx_i32m1(vidx, i * 3, vl);
    vb            = __riscv_vrem_vx_i32m1(vb, 5, vl);
    __riscv_vse32_v_i32m1(&AT(B, i, 0), vb, vl);
  }
}

/* Outer-product RVV GEMM: for each row i of C, accumulate
 *   C[i][:] += A[i][k] * B[k][:]
 * using a single V register per row. */
static void vmatmul_kernel(void)
{
  for (int i = 0; i < N; i++) {
    size_t     vl   = __riscv_vsetvl_e32m1((size_t) N);
    vint32m1_t vacc = __riscv_vmv_v_x_i32m1(0, vl);
    for (int k = 0; k < N; k++) {
      const int32_t  a_ik = AT(A, i, k);
      const vint32m1_t vb_k =
        __riscv_vle32_v_i32m1(&AT(B, k, 0), vl);
      vacc = __riscv_vmacc_vx_i32m1(vacc, a_ik, vb_k, vl);
    }
    __riscv_vse32_v_i32m1(&AT(C, i, 0), vacc, vl);
  }
}

/* Pure scalar reference, independent of the RVV kernel above. */
static int scalar_matmul_verify(void)
{
  for (int i = 0; i < N; i++) {
    for (int j = 0; j < N; j++) {
      int32_t s = 0;
      for (int k = 0; k < N; k++)
        s += AT(A, i, k) * AT(B, k, j);
      if (AT(C, i, j) != s)
        return 0;
    }
  }
  return 1;
}

int main(void)
{
  /* Phase 1 (QEMU 1): seed inputs only. */
  init_matrices();

  enter_vsim();

  /* Phase 2 (vsim): RVV kernel only. No I/O permitted. */
  vmatmul_kernel();

  exit_vsim();

  /* Phase 3 (QEMU 2): scalar reference compare. */
  if (!scalar_matmul_verify()) {
    printf("rt_c_v_matmul: FAIL\n");
    fflush(stdout);
    return 1;
  }
  printf("rt_c_v_matmul: PASS\n");
  fflush(stdout);
  return 0;
}

/* Tier-2 C-level fixture: 16x16x16 GEMM split across all three phases.
 *
 *   QEMU 1: init_matrices -- fills A and B with deterministic patterns.
 *   vsim:   matmul_kernel -- pure C = A * B, no syscalls (phase-2 rule).
 *   QEMU 2: prints C row-by-row via printf, then re-derives the expected
 *           value of every C[i][j] and compares. Mismatch -> _exit(1).
 *
 * Cross-phase memory survival
 *   Matrices sit in .bss. The "no redundant ELF reload" rule (vsim
 *   skips load_elf and QEMU 2 drops -kernel when --shared-mem-path is
 *   set) keeps phase-1 .bss writes intact through the shared
 *   memory-backend-file.
 */
#include "runtime/rt_c_helpers.h"

#include <stdint.h>
#include <stdio.h>

#define N 16

static int32_t A[N * N];
static int32_t B[N * N];
static int32_t C[N * N];

#define AT(M, i, j) ((M)[(i) *N + (j)])

static void init_matrices(void)
{
  for (int i = 0; i < N; i++) {
    for (int j = 0; j < N; j++) {
      AT(A, i, j) = (int32_t) ((i + j) % 7);
      AT(B, i, j) = (int32_t) ((i * 3 + j) % 5);
    }
  }
}

static void matmul_kernel(void)
{
  for (int i = 0; i < N; i++) {
    for (int j = 0; j < N; j++) {
      int32_t s = 0;
      for (int k = 0; k < N; k++) {
        s += AT(A, i, k) * AT(B, k, j);
      }
      AT(C, i, j) = s;
    }
  }
}

/* Independent recomputation in QEMU2 -- catches any kernel error. */
static int verify(void)
{
  for (int i = 0; i < N; i++) {
    for (int j = 0; j < N; j++) {
      int32_t s = 0;
      for (int k = 0; k < N; k++) {
        s += AT(A, i, k) * AT(B, k, j);
      }
      if (AT(C, i, j) != s)
        return 0;
    }
  }
  return 1;
}

int main(void)
{
  /* Phase 1 (QEMU 1): seed inputs. */
  init_matrices();

  enter_vsim();

  /* Phase 2 (vsim): GEMM kernel only. No syscalls. */
  matmul_kernel();

  exit_vsim();

  /* Phase 3 (QEMU 2): print + verify. */
  printf("rt_c_matmul: C[16][16]=\n");
  for (int i = 0; i < N; i++) {
    for (int j = 0; j < N; j++)
      printf("%4d ", (int) AT(C, i, j));
    printf("\n");
  }

  if (!verify()) {
    printf("rt_c_matmul: FAIL\n");
    fflush(stdout);
    return 1;
  }
  printf("rt_c_matmul: PASS\n");
  fflush(stdout);
  return 0;
}

// V-register transport via shared scratch RAM. The vsim Debug Module
// abstract-command space does not allocate slots for v0..v31 (RISC-V Debug
// Spec leaves V to optional Program Buffer or implementation-specific
// extensions), and the AX45MPV CPU wrapper does not export a DPI probe for
// the V regfile. As a stop-gap that keeps Phase 5 (DPI / PB) deferred while
// still letting C-level RVV fixtures round-trip:
//
//   - On resume from QEMU 1, vsim copies state.vreg[] into a fixed scratch
//     region of guest RAM (kVScratchGpa). The fixture's vsim-phase prologue
//     issues `vle8.v vN, (t0)` against that region to repopulate v0..v31.
//   - Before the vsim->QEMU2 drain trigger, the fixture issues `vse8.v vN,
//     (t0)` to write the (possibly mutated) regfile back to the same region.
//     vsim's StateDrain side reads the scratch bytes into state.vreg[] so
//     qemu_handback can ship them to QEMU 2 via the existing gdbstub P
//     packets.
//
// The contract is fixture-aware: any program that wants V state preserved
// across the vsim boundary must perform the load/store at the boundaries.
// rt_c_v_regs.c demonstrates the pattern. Phase 5 will replace this with a
// transparent mechanism (PB or DPI) so benchmark binaries don't need to be
// modified.
//
// Pure logic: no SystemC, no DMI bus. Easy to unit-test.

#pragma once

#include "hybrid/state_abi.h"

#include <cstddef>
#include <cstdint>
#include <cstring>
#include <span>
#include <stdexcept>

namespace hybrid
{

// Top of QEMU virt's default 128 MiB RAM (RAM_BASE 0x80000000 + 0x0FF0000
// = 0x80FF0000). Below the C-runtime stack at 0x80700000 only when the
// runtime grows beyond default; rt_c.ld places _stack at 0x80700000 so
// 0x80FF0000 sits well above it. Document the reservation in fixture
// comments so future memory-layout changes don't collide.
inline constexpr uint64_t kVScratchGpa = 0x80FF0000ull;

// Total scratch bytes needed: 32 V regs × HYBRID_VLEN_BYTES_MAX. Sized to
// the maximum supported VLEN; the actual per-reg byte count is `vlenb`.
inline constexpr std::size_t kVScratchBytes =
  static_cast<std::size_t>(32) * HYBRID_VLEN_BYTES_MAX;

namespace detail
{

// Translate scratch GPA into a byte offset inside a RAM span whose first
// byte sits at `ram_base`. Throws if the scratch region falls outside the
// supplied span (i.e. the caller passed a too-small RAM mapping).
inline auto scratch_offset(std::size_t ram_size, uint64_t ram_base)
  -> std::size_t
{
  if (kVScratchGpa < ram_base)
    throw std::runtime_error(
      "v_regfile_xfer: scratch GPA below RAM base");
  const auto off = static_cast<std::size_t>(kVScratchGpa - ram_base);
  if (off + kVScratchBytes > ram_size)
    throw std::runtime_error(
      "v_regfile_xfer: scratch region exceeds RAM span");
  return off;
}

}  // namespace detail

// Copy state.vreg[] into ram[scratch_offset .. scratch_offset+kVScratchBytes].
// Called just before vsim resumes the hart so the fixture can vle8.v from
// scratch and pick up QEMU 1's V values.
inline void stage_v_to_scratch(const hybrid_state_v1& state,
                               std::span<uint8_t> ram,
                               uint64_t ram_base)
{
  const auto off = detail::scratch_offset(ram.size(), ram_base);
  std::memcpy(ram.data() + off, state.vreg, kVScratchBytes);
}

// Copy ram[scratch_offset .. +kVScratchBytes] into state.vreg[]. Called
// inside the vsim drain path after the fixture's prologue vse8.v has
// settled the (possibly mutated) regfile bytes into RAM.
inline void read_v_from_scratch(hybrid_state_v1& state,
                                std::span<const uint8_t> ram,
                                uint64_t ram_base)
{
  const auto off = detail::scratch_offset(ram.size(), ram_base);
  std::memcpy(state.vreg, ram.data() + off, kVScratchBytes);
}

}  // namespace hybrid

